import{_ as e,o as a,c as r,a0 as i}from"./chunks/framework.NWv86GGy.js";const h=JSON.parse('{"title":"Brazil — Country Brief","description":"Trans relocation guide for Brazil: legal overview, visa options, cost of living, and key considerations.","frontmatter":{"layout":"doc","title":"Brazil — Country Brief","description":"Trans relocation guide for Brazil: legal overview, visa options, cost of living, and key considerations."},"headers":[],"relativePath":"countries/brazil/index.md","filePath":"countries/brazil/index.md","lastUpdated":1780601195000}'),o={name:"countries/brazil/index.md"};function n(s,t,l,d,g,c){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="🇧🇷-brazil" tabindex="-1"><span style="color:#009739;">🇧🇷 Brazil</span> <a class="header-anchor" href="#🇧🇷-brazil" aria-label="Permalink to &quot;&lt;span style=&quot;color: #009739;&quot;&gt;🇧🇷 Brazil&lt;/span&gt;&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Capital</strong></td><td>Brasília</td></tr><tr><td><strong>Language</strong></td><td>Portuguese (limited English)</td></tr><tr><td><strong>Currency</strong></td><td>Brazilian Real (BRL)</td></tr><tr><td><strong>Equaldex Score</strong></td><td>75</td></tr><tr><td><strong>Trans-Specific Rating</strong></td><td>Laws: 4/5, Safety: 2/5</td></tr><tr><td><strong>Last Verified</strong></td><td>June 2026</td></tr></tbody></table><h2 id="legal-overview" tabindex="-1">Legal Overview <a class="header-anchor" href="#legal-overview" aria-label="Permalink to &quot;Legal Overview&quot;">​</a></h2><ul><li><strong>Gender Recognition:</strong> Self-ID since 2018 (Supreme Court ruling). No surgery or therapy required. Change at registry office.</li><li><strong>Anti-Discrimination Law:</strong> Supreme Court rulings provide protections. Federal anti-discrimination bill pending.</li><li><strong>Hate Crime Laws:</strong> 2019 Supreme Court ruling criminalises homophobia and transphobia (pending federal legislation).</li><li><strong>Same-Sex Marriage:</strong> Legal since 2013 (Supreme Court ruling).</li></ul><h2 id="healthcare" tabindex="-1">Healthcare <a class="header-anchor" href="#healthcare" aria-label="Permalink to &quot;Healthcare&quot;">​</a></h2><ul><li><strong>HRT Access:</strong> Informed consent available. Public SUS system covers gender-affirming care by law.</li><li><strong>Cost:</strong> Free on SUS. Private: BRL 100–400/month (≈ €18–72).</li></ul><h2 id="visa-pathways" tabindex="-1">Visa Pathways <a class="header-anchor" href="#visa-pathways" aria-label="Permalink to &quot;Visa Pathways&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Income Req.</th><th>Processing</th><th>Leads to PR?</th></tr></thead><tbody><tr><td>Digital Nomad Visa</td><td>No fixed minimum</td><td>1–3 months</td><td>Renewable</td></tr><tr><td>Work Visa</td><td>Job offer</td><td>2–6 months</td><td>Yes</td></tr><tr><td>Student Visa</td><td>Proof of funds</td><td>1–3 months</td><td>Possible</td></tr></tbody></table><h2 id="cost-of-living-sao-paulo-rio" tabindex="-1">Cost of Living (São Paulo/Rio) <a class="header-anchor" href="#cost-of-living-sao-paulo-rio" aria-label="Permalink to &quot;Cost of Living (São Paulo/Rio)&quot;">​</a></h2><p>1-bedroom: BRL 2,000–4,500/month (≈ €360–800). Monthly budget: BRL 5,000–10,000 (≈ €900–1,800). Very affordable for those earning foreign currency.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li><strong>⚠️ Situation rapidly changing:</strong> Strong legal framework but rising political violence</li><li><strong>Highest trans murder rate in the world</strong> — Brazil is extremely dangerous for trans women, especially those in sex work</li><li><strong>Inflation and economic instability</strong> affect daily life</li><li><strong>Portuguese essential</strong> for integration</li><li><strong>Large, visible trans community</strong> in São Paulo and Rio</li><li><strong>Asylum:</strong> Not recommended; safety concerns outweigh legal protections for most</li></ul><p><em>Sources: ANTRA (Associação Nacional de Travestis e Transexuais), ILGA, Equaldex. Last verified: June 2026.</em></p>',13)])])}const f=e(o,[["render",n]]);export{h as __pageData,f as default};
